func (p *CypherParser) ReservedWord() (localctx IReservedWordContext) {
	localctx = NewReservedWordContext(p, p.GetParserRuleContext(), p.GetState())
	p.EnterRule(localctx, 178, CypherParserRULE_reservedWord)
	var _la int

	p.EnterOuterAlt(localctx, 1)
	{
		p.SetState(838)
		_la = p.GetTokenStream().LA(1)

		if !((int64((_la-36)) & ^0x3f) == 0 && ((int64(1)<<(_la-36))&9007199254740991) != 0) {
			p.GetErrorHandler().RecoverInline(p)
		} else {
			p.GetErrorHandler().ReportMatch(p)
			p.Consume()
		}
	}

	if p.HasError() {
		v := p.GetError()
		localctx.SetException(v)
		p.GetErrorHandler().ReportError(p, v)
		p.GetErrorHandler().Recover(p, v)
		p.SetError(nil)
	}
	p.ExitRule()
	return localctx
}

// ─────────────────────────────────────────────────────────────────────────────
// Numeric-ID workarounds (vendored from the post-generation patch suite)
//
// The vendored Cypher grammar's lexer orders `ID: LetterOrDigit+` before
// `DIGIT: ...`, so positive integers in expressions (e.g. `3`, `42`, range
// bounds inside `[r*1..3]`) tokenise as ID rather than DIGIT. The Atom,
// Literal, NumLit, and RangeLit rules above call into the helpers below so
// numeric-ID tokens are accepted wherever the grammar expects DIGIT.
//
// These helpers are kept at the end of the file so they survive ANTLR
// regeneration (the generator never emits anything at this location). If you
// re-run `make generate-cypher-parser`, you MUST re-apply the surgical edits
// to Atom, Literal, NumLit, and RangeLit, plus restore this block — see
// docs/tck/parser-report.md for the canonical recipe.
// ─────────────────────────────────────────────────────────────────────────────

// isNumericIDToken reports whether tok is an ID token whose text consists
// entirely of ASCII decimal digits (e.g. "3", "42", "100"). This is the
// canonical check used by the numeric-ID workarounds throughout this file.
func isNumericIDToken(tok antlr.Token) bool {
	if tok == nil {
		return false
	}
	if tok.GetTokenType() != CypherParserID {
		return false
	}
	text := tok.GetText()
	if len(text) == 0 {
		return false
	}
	for _, ch := range text {
		if ch < '0' || ch > '9' {
			return false
		}
	}
	return true
}

// rangeNumBound consumes a DIGIT or a purely-numeric ID token and adds it as a
// child terminal of the current rule context. This is a targeted workaround
// for the ANTLR lexer ambiguity where single- or multi-digit integers inside a
// range-literal (e.g. [r*1..3]) are tokenised as ID instead of DIGIT because
// the ID rule (LetterOrDigit+) appears before DIGIT in the lexer grammar.
//
// The approach:
//  1. Peek at the next token. Accept it if it is DIGIT, or if it is ID and its
//     text consists entirely of ASCII digits.
//  2. Consume the token so the token-stream cursor advances past it.
//  3. Wrap the consumed token in a TerminalNode and add it to the current
//     rule context so ctx.GetText() returns the expected concatenated text
//     (e.g. "*1..3").
//
// If the next token is neither DIGIT nor a numeric ID, this is a no-op.
func (p *CypherParser) rangeNumBound() {
	tok := p.GetTokenStream().LT(1)
	if tok == nil {
		return
	}
	if tok.GetTokenType() == CypherParserDIGIT || isNumericIDToken(tok) {
		p.GetTokenStream().Consume()
		p.GetParserRuleContext().AddTokenNode(tok) //nolint:staticcheck // generated-parser pattern
	}
}
